import React, { useState, useEffect, useCallback } from 'react';
import { useBrand } from '../context/BrandContext';

interface TourStep {
  target: string;
  title: string;
  content: string;
  placement?: 'top' | 'bottom' | 'left' | 'right';
}

const TOUR_STEPS: TourStep[] = [
  {
    target: '[data-tour="resume-upload"]',
    title: 'Upload Your Resume',
    content: 'Start by uploading your resume (PDF, DOCX, or plain text). You can also save multiple profiles for different roles.',
    placement: 'bottom',
  },
  {
    target: '[data-tour="job-description"]',
    title: 'Paste the Job Description',
    content: 'Copy the job listing and paste it here. Our AI will analyze keywords and requirements to tailor your resume.',
    placement: 'bottom',
  },
  {
    target: '[data-tour="tools-grid"]',
    title: 'Explore AI Tools',
    content: '26 AI career tools — from cover letters to salary negotiation. Free users get one try of each tool.',
    placement: 'top',
  },
  {
    target: '[data-tour="theme-toggle"]',
    title: 'Dark / Light Mode',
    content: 'Toggle between dark and light mode anytime. Your preference is saved automatically.',
    placement: 'bottom',
  },
  {
    target: '[data-tour="product-switcher"]',
    title: 'Switch Products',
    content: 'Jump between TailorMeSwiftly, TailorTheNews, and our Learning Hub from the app grid.',
    placement: 'bottom',
  },
];

const STORAGE_KEY = 'tms_onboarded';

export default function OnboardingTour() {
  const brand = useBrand();
  const [currentStep, setCurrentStep] = useState(-1);
  const [spotlightRect, setSpotlightRect] = useState<DOMRect | null>(null);
  const [dismissed, setDismissed] = useState(false);

  useEffect(() => {
    if (localStorage.getItem(STORAGE_KEY)) {
      setDismissed(true);
    }
  }, []);

  const startTour = useCallback(() => {
    setCurrentStep(0);
  }, []);

  const nextStep = useCallback(() => {
    if (currentStep >= TOUR_STEPS.length - 1) {
      endTour();
      return;
    }
    setCurrentStep(prev => prev + 1);
  }, [currentStep]);

  const endTour = useCallback(() => {
    setCurrentStep(-1);
    setSpotlightRect(null);
    localStorage.setItem(STORAGE_KEY, 'true');
    setDismissed(true);
  }, []);

  // Update spotlight position when step changes
  useEffect(() => {
    if (currentStep < 0 || currentStep >= TOUR_STEPS.length) {
      setSpotlightRect(null);
      return;
    }

    const step = TOUR_STEPS[currentStep];
    const el = document.querySelector(step.target);
    if (el) {
      const rect = el.getBoundingClientRect();
      setSpotlightRect(rect);
      el.scrollIntoView({ behavior: 'smooth', block: 'center' });
    } else {
      // Skip step if element not found
      setSpotlightRect(null);
    }
  }, [currentStep]);

  // Show start prompt for first-time users
  if (!dismissed && currentStep < 0) {
    return (
      <div style={{
        position: 'fixed',
        bottom: '1.5rem',
        right: '1.5rem',
        background: 'var(--panel-bg)',
        border: '1px solid var(--panel-border)',
        borderRadius: 'var(--brutal-radius, 2px)',
        padding: '1.25rem',
        maxWidth: '300px',
        boxShadow: 'var(--brutal-shadow, 2px 2px 0 rgba(0,0,0,0.25))',
        zIndex: 900,
      }}>
        <h4 style={{ margin: '0 0 0.5rem', color: 'var(--text-primary)', fontSize: '0.95rem' }}>
          <i className="fa-solid fa-hand-sparkles" style={{ color: brand.primaryColor, marginRight: '0.4rem' }} />
          Welcome to TailorMeSwiftly!
        </h4>
        <p style={{ color: 'var(--text-secondary)', fontSize: '0.82rem', margin: '0 0 1rem', lineHeight: 1.5 }}>
          Take a quick tour to learn how to tailor your resume with AI.
        </p>
        <div style={{ display: 'flex', gap: '0.5rem' }}>
          <button
            onClick={endTour}
            className="btn ghost-btn"
            style={{
              fontSize: '0.82rem',
            }}
          >
            Skip
          </button>
          <button
            onClick={startTour}
            className="btn secondary-btn"
            style={{
              flex: 1,
              fontSize: '0.82rem',
              background: brand.primaryColor,
              color: '#fff',
            }}
          >
            Show me around
          </button>
        </div>
      </div>
    );
  }

  if (currentStep < 0 || currentStep >= TOUR_STEPS.length) return null;

  const step = TOUR_STEPS[currentStep];

  // Calculate tooltip position
  const tooltipStyle: React.CSSProperties = {
    position: 'fixed',
    background: 'var(--panel-bg)',
    border: `2px dashed ${brand.primaryColor}`,
    borderRadius: 'var(--brutal-radius, 2px)',
    padding: '1.25rem',
    maxWidth: '320px',
    boxShadow: 'var(--brutal-shadow, 2px 2px 0 rgba(0,0,0,0.25))',
    zIndex: 1002,
  };

  if (spotlightRect) {
    const placement = step.placement || 'bottom';
    if (placement === 'bottom') {
      tooltipStyle.top = `${spotlightRect.bottom + 12}px`;
      tooltipStyle.left = `${Math.max(16, spotlightRect.left)}px`;
    } else if (placement === 'top') {
      tooltipStyle.bottom = `${window.innerHeight - spotlightRect.top + 12}px`;
      tooltipStyle.left = `${Math.max(16, spotlightRect.left)}px`;
    } else if (placement === 'right') {
      tooltipStyle.top = `${spotlightRect.top}px`;
      tooltipStyle.left = `${spotlightRect.right + 12}px`;
    } else {
      tooltipStyle.top = `${spotlightRect.top}px`;
      tooltipStyle.right = `${window.innerWidth - spotlightRect.left + 12}px`;
    }
  } else {
    tooltipStyle.top = '50%';
    tooltipStyle.left = '50%';
    tooltipStyle.transform = 'translate(-50%, -50%)';
  }

  return (
    <>
      {/* Backdrop */}
      <div
        onClick={endTour}
        style={{
          position: 'fixed',
          inset: 0,
          background: 'rgba(0,0,0,0.6)',
          zIndex: 1000,
        }}
      />

      {/* Spotlight cutout */}
      {spotlightRect && (
        <div style={{
          position: 'fixed',
          top: `${spotlightRect.top - 6}px`,
          left: `${spotlightRect.left - 6}px`,
          width: `${spotlightRect.width + 12}px`,
          height: `${spotlightRect.height + 12}px`,
          borderRadius: 'var(--brutal-radius, 2px)',
          boxShadow: '0 0 0 9999px rgba(0,0,0,0.6)',
          zIndex: 1001,
          pointerEvents: 'none',
        }} />
      )}

      {/* Tooltip */}
      <div style={tooltipStyle}>
        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start', marginBottom: '0.5rem' }}>
          <h4 style={{ margin: 0, color: 'var(--text-primary)', fontSize: '0.95rem' }}>
            {step.title}
          </h4>
          <span style={{ color: 'var(--text-secondary)', fontSize: '0.72rem', whiteSpace: 'nowrap', marginLeft: '0.5rem' }}>
            {currentStep + 1}/{TOUR_STEPS.length}
          </span>
        </div>
        <p style={{ color: 'var(--text-secondary)', fontSize: '0.82rem', margin: '0 0 1rem', lineHeight: 1.5 }}>
          {step.content}
        </p>
        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
          <button
            onClick={endTour}
            style={{
              background: 'none',
              border: 'none',
              color: 'var(--text-secondary)',
              cursor: 'pointer',
              fontSize: '0.78rem',
              padding: 0,
            }}
          >
            Skip tour
          </button>
          <button
            onClick={nextStep}
            className="btn secondary-btn"
            style={{
              fontSize: '0.82rem',
              background: brand.primaryColor,
              color: '#fff',
            }}
          >
            {currentStep === TOUR_STEPS.length - 1 ? 'Done' : 'Next'}
          </button>
        </div>
      </div>
    </>
  );
}
