import React, { createContext, useContext, useState, useCallback, useRef, useEffect } from 'react';

interface ToastMessage {
  id: number;
  text: string;
  isError: boolean;
}

interface ToastContextValue {
  showToast: (message: string, isError?: boolean) => void;
}

const ToastContext = createContext<ToastContextValue>({ showToast: () => {} });

let nextId = 0;

export function ToastProvider({ children }: { children: React.ReactNode }) {
  const [toasts, setToasts] = useState<ToastMessage[]>([]);
  const timersRef = useRef<Map<number, ReturnType<typeof setTimeout>>>(new Map());

  const showToast = useCallback((message: string, isError = false) => {
    const id = nextId++;
    setToasts(prev => [...prev, { id, text: message, isError }]);

    const timer = setTimeout(() => {
      setToasts(prev => prev.filter(t => t.id !== id));
      timersRef.current.delete(id);
    }, 4000);
    timersRef.current.set(id, timer);
  }, []);

  useEffect(() => {
    // Expose globally for backward compatibility
    (window as unknown as Record<string, unknown>).showToast = showToast;
  }, [showToast]);

  return (
    <ToastContext.Provider value={{ showToast }}>
      {children}
      <div
        style={{
          position: 'fixed',
          bottom: '2rem',
          left: '50%',
          transform: 'translateX(-50%)',
          zIndex: 10000,
          display: 'flex',
          flexDirection: 'column',
          gap: '0.5rem',
          alignItems: 'center',
          pointerEvents: 'none',
        }}
      >
        {toasts.map(toast => (
          <div
            key={toast.id}
            role="status"
            aria-live="polite"
            style={{
              padding: '0.75rem 1.5rem',
              borderRadius: '8px',
              fontSize: '0.9rem',
              maxWidth: '90vw',
              textAlign: 'center',
              animation: 'toastIn 0.3s ease',
              background: toast.isError ? '#3a2020' : '#1a2a1a',
              color: toast.isError ? '#E3A8B3' : '#8A9A86',
              border: toast.isError
                ? '1px solid rgba(227,168,179,0.3)'
                : '1px solid rgba(138,154,134,0.3)',
            }}
          >
            {toast.text}
          </div>
        ))}
      </div>
    </ToastContext.Provider>
  );
}

export function useToast(): ToastContextValue {
  return useContext(ToastContext);
}
