import React from 'react';
import { Link } from 'react-router-dom';
import { useBrand, NavItem } from '../../context/BrandContext';

export default function Footer() {
  const brand = useBrand();

  const links: NavItem[] = brand.footerLinks || [
    { href: '/pricing', label: 'Pricing', icon: '' },
    { href: '/blog.html', label: 'Blog', icon: '', external: true },
    { href: '/help', label: 'Help', icon: '' },
    { href: '/terms', label: 'Terms & Conditions', icon: '' },
    { href: '/privacy', label: 'Privacy Policy', icon: '' },
    { href: '/security', label: 'Security Policy', icon: '' },
  ];

  return (
    <footer className="site-footer" role="contentinfo">
      <p>&copy; {new Date().getFullYear()} TailorMeSwiftly.com. One platform for your entire career trajectory.</p>
      <p>
        {links.map((link, i) => (
          <React.Fragment key={link.href}>
            {i > 0 && ' | '}
            {link.external ? (
              <a href={link.href}>{link.label}</a>
            ) : (
              <Link to={link.href}>{link.label}</Link>
            )}
          </React.Fragment>
        ))}
      </p>
    </footer>
  );
}
