import React, { useState, useRef, useEffect } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { useAuth } from '../../context/SupabaseContext';
import { useBrand } from '../../context/BrandContext';
import { useTheme } from '../../context/ThemeContext';
import ProductSwitcher from './ProductSwitcher';

export default function NavHeader() {
  const { user, signOut } = useAuth();
  const brand = useBrand();
  const { theme, toggleTheme } = useTheme();
  const navigate = useNavigate();
  const [dropdownOpen, setDropdownOpen] = useState(false);
  const dropdownRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    function handleClick(e: MouseEvent) {
      if (dropdownRef.current && !dropdownRef.current.contains(e.target as Node)) {
        setDropdownOpen(false);
      }
    }
    document.addEventListener('click', handleClick);
    return () => document.removeEventListener('click', handleClick);
  }, []);

  const firstName = user
    ? (user.user_metadata?.full_name || user.email || '').split(/[\s@]/)[0]
    : '';

  const avatarUrl = user?.user_metadata?.avatar_url
    || (user ? `https://ui-avatars.com/api/?background=random&name=${encodeURIComponent(user.email || '')}` : '');

  return (
    <header className="app-header" role="banner">
      {/* Logo — Maker's Mark (matches vanilla) */}
      <Link to="/" className="logo maker-mark" style={{ textDecoration: 'none', color: 'inherit' }}>
        <span className="mark-border">
          <span className="mark-text">TMS</span>
        </span>
        <div className="mark-name">
          <span className="mark-script">TailorMeSwiftly</span>
          <span className="mark-sub">BESPOKE APPLICATION ENGINE</span>
        </div>
      </Link>

      {/* Right side actions */}
      <div className="header-actions" style={{ display: 'flex', gap: '1rem', alignItems: 'center' }}>
        <ProductSwitcher />

        {user ? (
          <div ref={dropdownRef} id="user-profile" className="user-profile" style={{ position: 'relative', display: 'flex', alignItems: 'center', gap: '0.5rem' }}>
            <img
              src={avatarUrl}
              alt={firstName}
              onClick={() => setDropdownOpen(v => !v)}
              style={{
                width: '36px',
                height: '36px',
                borderRadius: '50%',
                objectFit: 'cover',
                border: '2px solid var(--primary-color)',
                cursor: 'pointer',
              }}
            />
            <span
              onClick={() => setDropdownOpen(v => !v)}
              style={{ fontSize: '0.7rem', color: 'var(--text-secondary)', cursor: 'pointer' }}
            >
              Hi, {firstName}
            </span>

            {dropdownOpen && (
              <div className="avatar-dropdown">
                {brand.navItems.map(item => (
                  item.external ? (
                    <a
                      key={item.href}
                      href={item.href}
                      className="dropdown-item"
                      onClick={() => setDropdownOpen(false)}
                      style={{ textDecoration: 'none', color: 'inherit' }}
                    >
                      <i className={`fa-solid ${item.icon}`} /> {item.label}
                    </a>
                  ) : (
                    <Link
                      key={item.href}
                      to={item.href}
                      className="dropdown-item"
                      onClick={() => setDropdownOpen(false)}
                      style={{ textDecoration: 'none', color: 'inherit' }}
                    >
                      <i className={`fa-solid ${item.icon}`} /> {item.label}
                    </Link>
                  )
                ))}
                {/* Theme toggle as a dropdown item */}
                <button
                  className="dropdown-item"
                  onClick={toggleTheme}
                  style={{ background: 'transparent', border: 'none', cursor: 'pointer', color: 'inherit', width: '100%', textAlign: 'left' }}
                >
                  <i className={`fa-solid ${theme === 'dark' ? 'fa-sun' : 'fa-moon'}`} /> {theme === 'dark' ? 'Light Mode' : 'Dark Mode'}
                </button>
                <button
                  className="dropdown-item"
                  id="logout-btn"
                  aria-label="Sign out"
                  onClick={async () => {
                    setDropdownOpen(false);
                    await signOut();
                    navigate('/');
                  }}
                  style={{ background: 'transparent', border: 'none', cursor: 'pointer', color: 'inherit', width: '100%', textAlign: 'left' }}
                >
                  <i className="fa-solid fa-arrow-right-from-bracket" /> Sign Out
                </button>
              </div>
            )}
          </div>
        ) : (
          <Link to="/login" id="login-btn" className="btn ghost-btn" style={{ fontSize: '0.85rem' }}>
            Log In
          </Link>
        )}
      </div>
    </header>
  );
}
