import React, { lazy, Suspense } from 'react';
import { Routes, Route } from 'react-router-dom';
import AppShell from './components/layout/AppShell';

// Lazy-load pages for code splitting
const LandingPage = lazy(() => import('./pages/LandingPage'));
const WizardPage = lazy(() => import('./pages/WizardPage'));
const ResumeEditor = lazy(() => import('./App'));
const ResultsPage = lazy(() => import('./pages/ResultsPage'));
const DashboardPage = lazy(() => import('./pages/DashboardPage'));
const HistoryPage = lazy(() => import('./pages/HistoryPage'));
const LoginPage = lazy(() => import('./pages/LoginPage'));
const SignupPage = lazy(() => import('./pages/SignupPage'));
const AccountPage = lazy(() => import('./pages/AccountPage'));
const PricingPage = lazy(() => import('./pages/PricingPage'));
const ToolPage = lazy(() => import('./pages/ToolPage'));
const SharePage = lazy(() => import('./pages/SharePage'));
const AnalyticsDashboard = lazy(() => import('./pages/AnalyticsDashboard'));
const SalaryBenchmarkingPage = lazy(() => import('./pages/SalaryBenchmarkingPage'));
const JobMarketHeatmapPage = lazy(() => import('./pages/JobMarketHeatmapPage'));
const MockInterviewPage = lazy(() => import('./pages/MockInterviewPage'));
const TermsPage = lazy(() => import('./pages/TermsPage'));
const PrivacyPage = lazy(() => import('./pages/PrivacyPage'));
const SecurityPage = lazy(() => import('./pages/SecurityPage'));
const HelpPage = lazy(() => import('./pages/HelpPage'));
const FeedbackPage = lazy(() => import('./pages/FeedbackPage'));
const JobTrackerPage = lazy(() => import('./pages/JobTrackerPage'));
const ForgotPasswordPage = lazy(() => import('./pages/ForgotPasswordPage'));
const NotFoundPage = lazy(() => import('./pages/NotFoundPage'));

function PageLoader() {
  return (
    <div style={{
      display: 'flex',
      alignItems: 'center',
      justifyContent: 'center',
      minHeight: '60vh',
      color: 'var(--text-secondary, #8b949e)',
      fontSize: '0.9rem',
    }}>
      <i className="fa-solid fa-spinner fa-spin" style={{ marginRight: '0.5rem' }} />
      Loading...
    </div>
  );
}

export default function AppRouter() {
  return (
    <Suspense fallback={<PageLoader />}>
      <Routes>
        {/* Pages WITHOUT AppShell (full-screen layouts) */}
        <Route path="/resume" element={<ResumeEditor />} />

        {/* Pages WITH AppShell (header + footer) */}
        <Route element={<AppShell />}>
          <Route index element={<LandingPage />} />
          <Route path="/tailor" element={<WizardPage />} />
          <Route path="/results" element={<ResultsPage />} />
          <Route path="/dashboard" element={<DashboardPage />} />
          <Route path="/history" element={<HistoryPage />} />
          <Route path="/jobs" element={<JobTrackerPage />} />
          <Route path="/login" element={<LoginPage />} />
          <Route path="/signup" element={<SignupPage />} />
          <Route path="/forgot-password" element={<ForgotPasswordPage />} />
          <Route path="/account" element={<AccountPage />} />
          <Route path="/pricing" element={<PricingPage />} />
          <Route path="/analytics" element={<AnalyticsDashboard />} />
          <Route path="/share/:slug" element={<SharePage />} />

          {/* Custom tool pages (must be before generic :slug catch-all) */}
          <Route path="/tools/salary-benchmarking" element={<SalaryBenchmarkingPage />} />
          <Route path="/tools/job-market-heatmap" element={<JobMarketHeatmapPage />} />
          <Route path="/mock-interview" element={<MockInterviewPage />} />

          {/* All other AI tools via generic ToolPage */}
          <Route path="/tools/:slug" element={<ToolPage />} />

          {/* Legal, Help & Feedback */}
          <Route path="/terms" element={<TermsPage />} />
          <Route path="/privacy" element={<PrivacyPage />} />
          <Route path="/security" element={<SecurityPage />} />
          <Route path="/help" element={<HelpPage />} />
          <Route path="/feedback" element={<FeedbackPage />} />

          {/* Catch-all */}
          <Route path="*" element={<NotFoundPage />} />
        </Route>
      </Routes>
    </Suspense>
  );
}
