import React, { Component, ErrorInfo } from 'react';

interface ErrorBoundaryProps {
  children: React.ReactNode;
  fallback?: React.ReactNode;
}

interface ErrorBoundaryState {
  hasError: boolean;
  error: Error | null;
}

export default class ErrorBoundary extends Component<ErrorBoundaryProps, ErrorBoundaryState> {
  constructor(props: ErrorBoundaryProps) {
    super(props);
    this.state = { hasError: false, error: null };
  }

  static getDerivedStateFromError(error: Error): ErrorBoundaryState {
    return { hasError: true, error };
  }

  componentDidCatch(error: Error, errorInfo: ErrorInfo) {
    // Log to Supabase error_logs table (existing infrastructure)
    this.logError(error, errorInfo);
  }

  async logError(error: Error, errorInfo: ErrorInfo) {
    try {
      // Use window.supabaseClient if available (exposed by SupabaseContext)
      const supabase = (window as unknown as Record<string, unknown>).supabaseClient as {
        from: (table: string) => { insert: (data: Record<string, unknown>) => Promise<unknown> };
      } | undefined;

      if (supabase) {
        await supabase.from('error_logs').insert({
          error_message: error.message,
          error_stack: error.stack?.substring(0, 2000),
          page_url: window.location.href,
          metadata: {
            error_type: 'react_boundary',
            component_stack: errorInfo.componentStack?.substring(0, 2000),
            user_agent: navigator.userAgent,
          },
        });
      }
    } catch {
      // Non-fatal — don't crash the error boundary
    }

    // Also log to console for dev visibility
    console.error('[ErrorBoundary] Caught error:', error);
    console.error('[ErrorBoundary] Component stack:', errorInfo.componentStack);
  }

  render() {
    if (this.state.hasError) {
      if (this.props.fallback) return this.props.fallback;

      return (
        <div className="glass-panel" style={{ maxWidth: '500px', margin: '4rem auto', padding: '2rem', textAlign: 'center' }}>
          <div style={{ fontSize: '3rem', marginBottom: '1rem' }}>
            <i className="fa-solid fa-triangle-exclamation" style={{ color: '#f59e0b' }} />
          </div>
          <h2 style={{ margin: '0 0 0.5rem', fontSize: '1.25rem' }}>Something went wrong</h2>
          <p style={{ color: 'var(--text-secondary)', fontSize: '0.85rem', margin: '0 0 1.5rem' }}>
            {this.state.error?.message || 'An unexpected error occurred.'}
          </p>
          <div style={{ display: 'flex', gap: '0.75rem', justifyContent: 'center' }}>
            <button onClick={() => window.location.reload()} className="btn primary-btn">
              <i className="fa-solid fa-rotate" /> Reload Page
            </button>
            <button onClick={() => { window.location.href = '/app/'; }} className="btn ghost-btn">
              <i className="fa-solid fa-house" /> Go Home
            </button>
          </div>
        </div>
      );
    }

    return this.props.children;
  }
}
