import React, { createContext, useContext, useEffect, useState, useCallback, useRef } from 'react';
import { createClient, SupabaseClient, Session, User, AuthChangeEvent } from '@supabase/supabase-js';

const SUPABASE_URL = 'https://gwmpdgjvcjzndbloctla.supabase.co';
const SUPABASE_KEY = 'sb_publishable_Kor1B60TEAKofYE75aW7Ow_WL0cPOa8';
const EDGE_BASE = SUPABASE_URL + '/functions/v1';
const STORAGE_KEY = 'sb-gwmpdgjvcjzndbloctla-auth-token';

interface AuthContextValue {
  supabase: SupabaseClient;
  user: User | null;
  session: Session | null;
  isPremium: boolean;
  isLoading: boolean;
  signInWithGoogle: (redirectTo?: string) => Promise<void>;
  signInWithEmail: (email: string, password: string) => Promise<{ error: string | null }>;
  signUp: (email: string, password: string) => Promise<{ error: string | null; needsConfirmation: boolean }>;
  signOut: () => Promise<void>;
  resetPassword: (email: string) => Promise<{ error: string | null }>;
  invokeEdgeFunction: (fnName: string, body?: Record<string, unknown>) => Promise<{ data: unknown; error: { message: string } | null }>;
}

const SupabaseContext = createContext<AuthContextValue | null>(null);

function isTokenExpired(token: string): boolean {
  try {
    const b64 = token.split('.')[1].replace(/-/g, '+').replace(/_/g, '/');
    const payload = JSON.parse(atob(b64));
    return payload.exp * 1000 < Date.now() + 30000;
  } catch {
    return true;
  }
}

function getStoredAccessToken(): string | null {
  try {
    const raw = localStorage.getItem(STORAGE_KEY);
    if (!raw) return null;
    const parsed = JSON.parse(raw);
    return parsed?.access_token || parsed?.currentSession?.access_token || null;
  } catch {
    return null;
  }
}

export function SupabaseProvider({ children }: { children: React.ReactNode }) {
  const [supabase] = useState(() =>
    createClient(SUPABASE_URL, SUPABASE_KEY, {
      auth: { autoRefreshToken: true, persistSession: true },
    })
  );
  const [user, setUser] = useState<User | null>(null);
  const [session, setSession] = useState<Session | null>(null);
  const [isPremium, setIsPremium] = useState(false);
  const [isLoading, setIsLoading] = useState(true);
  const signingOutRef = useRef(false);

  const checkPremiumStatus = useCallback(async (userId: string) => {
    try {
      const { data: proSub } = await supabase
        .from('user_subscriptions')
        .select('plan')
        .eq('user_id', userId)
        .eq('product_id', 'pro')
        .maybeSingle();

      if (proSub?.plan === 'premium') {
        setIsPremium(true);
        return;
      }

      const { data } = await supabase
        .from('user_profiles')
        .select('plan')
        .eq('user_id', userId)
        .maybeSingle();

      setIsPremium(data?.plan === 'premium');
    } catch {
      setIsPremium(false);
    }
  }, [supabase]);

  const getFreshToken = useCallback(async (): Promise<string | null> => {
    try {
      const { data: { session: s } } = await supabase.auth.getSession();
      if (s?.access_token && !isTokenExpired(s.access_token)) {
        return s.access_token;
      }
      if (s?.refresh_token) {
        const { data: refreshed } = await supabase.auth.refreshSession();
        if (refreshed?.session?.access_token) return refreshed.session.access_token;
      }
      const stored = getStoredAccessToken();
      if (stored && !isTokenExpired(stored)) return stored;
    } catch { /* silent */ }
    return null;
  }, [supabase]);

  const invokeEdgeFunction = useCallback(async (fnName: string, body: Record<string, unknown> = {}) => {
    let token = await getFreshToken();
    if (!token) {
      try {
        const { data: r } = await supabase.auth.refreshSession();
        token = r?.session?.access_token || null;
      } catch { /* silent */ }
      if (!token) return { data: null, error: { message: 'Not authenticated' } };
    }

    const resp = await fetch(`${EDGE_BASE}/${fnName}`, {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        'Authorization': `Bearer ${token}`,
      },
      body: JSON.stringify(body),
    });
    const json = await resp.json().catch(() => ({}));
    if (!resp.ok) {
      const errMsg = (json as Record<string, unknown>)?.message
        || ((json as Record<string, unknown>)?.error as Record<string, unknown>)?.message
        || (json as Record<string, unknown>)?.error
        || `Edge function error (${resp.status})`;
      return { data: null, error: { message: String(errMsg) } };
    }
    return { data: json, error: null };
  }, [getFreshToken, supabase]);

  const signInWithGoogle = useCallback(async (redirectTo?: string) => {
    const target = redirectTo || '/dashboard';
    const { error } = await supabase.auth.signInWithOAuth({
      provider: 'google',
      options: { redirectTo: new URL(target, window.location.href).href },
    });
    if (error) throw new Error(error.message);
  }, [supabase]);

  const signInWithEmail = useCallback(async (email: string, password: string) => {
    const { error } = await supabase.auth.signInWithPassword({ email, password });
    return { error: error?.message || null };
  }, [supabase]);

  const signUpFn = useCallback(async (email: string, password: string) => {
    const { error } = await supabase.auth.signUp({ email, password });
    if (error) return { error: error.message, needsConfirmation: false };
    return { error: null, needsConfirmation: true };
  }, [supabase]);

  const resetPassword = useCallback(async (email: string) => {
    const { error } = await supabase.auth.resetPasswordForEmail(email, {
      redirectTo: `${window.location.origin}/app/login`,
    });
    return { error: error?.message || null };
  }, [supabase]);

  const signOutFn = useCallback(async () => {
    signingOutRef.current = true;
    for (const key of Object.keys(localStorage)) {
      if (key.startsWith('sb-') || key.startsWith('tms_')) {
        localStorage.removeItem(key);
      }
    }
    sessionStorage.clear();
    try { await supabase.auth.signOut({ scope: 'local' }); } catch { /* ignore */ }
    setUser(null);
    setSession(null);
    setIsPremium(false);
    signingOutRef.current = false;
  }, [supabase]);

  useEffect(() => {
    // Get initial session
    supabase.auth.getSession().then(({ data: { session: s } }) => {
      setSession(s);
      setUser(s?.user ?? null);
      if (s?.user) checkPremiumStatus(s.user.id);
      setIsLoading(false);
    });

    // Listen for auth changes
    const { data: { subscription } } = supabase.auth.onAuthStateChange(
      (event: AuthChangeEvent, s: Session | null) => {
        if (signingOutRef.current) return;
        if (event === 'TOKEN_REFRESHED' && !s) return;

        setSession(s);
        setUser(s?.user ?? null);
        if (s?.user) {
          checkPremiumStatus(s.user.id);
        } else if (event === 'SIGNED_OUT') {
          setIsPremium(false);
        }
      }
    );

    return () => subscription.unsubscribe();
  }, [supabase, checkPremiumStatus]);

  // Expose supabase on window for backward compatibility with vanilla code
  useEffect(() => {
    (window as unknown as Record<string, unknown>).supabaseClient = supabase;
  }, [supabase]);

  return (
    <SupabaseContext.Provider
      value={{
        supabase,
        user,
        session,
        isPremium,
        isLoading,
        signInWithGoogle,
        signInWithEmail,
        signUp: signUpFn,
        signOut: signOutFn,
        resetPassword,
        invokeEdgeFunction,
      }}
    >
      {children}
    </SupabaseContext.Provider>
  );
}

export function useAuth(): AuthContextValue {
  const ctx = useContext(SupabaseContext);
  if (!ctx) throw new Error('useAuth must be used within SupabaseProvider');
  return ctx;
}
