import React, { createContext, useContext, useMemo } from 'react';
import { useLocation } from 'react-router-dom';

export interface Product {
  id: string;
  name: string;
  shortName: string;
  tagline: string;
  primaryColor: string;
  primaryHover: string;
  accentColor: string;
  accentGlow: string;
  icon: string;
  basePath: string;
  homePath: string;
  appPath: string;
}

export interface NavItem {
  href: string;
  icon: string;
  label: string;
  /** If true, render as <a> instead of React Router <Link> (for vanilla pages) */
  external?: boolean;
}

interface BrandContextValue {
  id: string;
  name: string;
  domain: string;
  tagline: string;
  primaryColor: string;
  primaryHover: string;
  accentColor: string;
  accentGlow: string;
  icon: string;
  homePath: string;
  appPath: string;
  navItems: NavItem[];
  footerLinks: NavItem[];
  activeProduct: Product;
  products: Record<string, Product>;
}

