function detectProduct(pathname: string): Product {
  if (pathname.startsWith('/news')) return products.news;
  if (pathname.startsWith('/learn')) return products.learn;
  return products.applications;
}

const BrandContext = createContext<BrandContextValue | null>(null);

export function BrandProvider({ children }: { children: React.ReactNode }) {
  const { pathname } = useLocation();

  const value = useMemo<BrandContextValue>(() => {
    const active = detectProduct(pathname);
    return {
      id: active.id,
      name: 'TailorMeSwiftly',
      domain: 'tailormeswiftly.com',
      tagline: active.tagline,
      primaryColor: active.primaryColor,
      primaryHover: active.primaryHover,
      accentColor: active.accentColor,
      accentGlow: active.accentGlow,
      icon: active.icon,
      homePath: active.homePath,
      appPath: active.appPath,
      navItems,
      footerLinks,
      activeProduct: active,
      products,
    };
  }, [pathname]);

  // Apply CSS variable overrides for non-TMS products
  useMemo(() => {
    const s = document.documentElement.style;
    const active = detectProduct(pathname);
    if (active.id !== 'tms') {
      s.setProperty('--primary-color', active.primaryColor);
      s.setProperty('--primary-hover', active.primaryHover);
      s.setProperty('--accent-color', active.accentColor);
      s.setProperty('--accent-glow', active.accentGlow);
    } else {
      s.removeProperty('--primary-color');
      s.removeProperty('--primary-hover');
      s.removeProperty('--accent-color');
      s.removeProperty('--accent-glow');
    }
  }, [pathname]);

  return <BrandContext.Provider value={value}>{children}</BrandContext.Provider>;
}

export function useBrand(): BrandContextValue {
  const ctx = useContext(BrandContext);
  if (!ctx) throw new Error('useBrand must be used within BrandProvider');
  return ctx;
}
