import {
  createContext,
  useContext,
  useReducer,
  useCallback,
  useMemo,
  type ReactNode,
} from 'react';
import type { DesignTokens, TypographyMode, DensityLevel } from '../types/sections';

// ============================================================
// DEFAULT TOKENS
// ============================================================

const DENSITY_PRESETS: Record<DensityLevel, Pick<DesignTokens['density'], 'lineHeight' | 'sectionGap' | 'itemGap' | 'marginBottom'>> = {
  compact:     { lineHeight: 1.3,  sectionGap: 12, itemGap: 2,  marginBottom: 4  },
  comfortable: { lineHeight: 1.5,  sectionGap: 20, itemGap: 6,  marginBottom: 8  },
  spacious:    { lineHeight: 1.75, sectionGap: 28, itemGap: 10, marginBottom: 12 },
};

const DEFAULT_TOKENS: DesignTokens = {
  typography: {
    mode: 'sans-serif',
    serifStack: '"Merriweather", "Georgia", "Times New Roman", serif',
    sansStack: '"Inter", "Outfit", "Helvetica Neue", Arial, sans-serif',
  },
  density: {
    level: 'comfortable',
    ...DENSITY_PRESETS.comfortable,
  },
  accent: {
    primary: '#10b981',
  },
};

// ============================================================
// ACTIONS
// ============================================================

type TokenAction =
  | { type: 'SET_TYPOGRAPHY'; mode: TypographyMode }
  | { type: 'SET_DENSITY'; level: DensityLevel }
  | { type: 'SET_ACCENT'; hex: string }
  | { type: 'RESET' };

function tokenReducer(state: DesignTokens, action: TokenAction): DesignTokens {
  switch (action.type) {
    case 'SET_TYPOGRAPHY':
      return {
        ...state,
        typography: { ...state.typography, mode: action.mode },
      };

    case 'SET_DENSITY':
      return {
        ...state,
        density: {
          level: action.level,
          ...DENSITY_PRESETS[action.level],
        },
      };

    case 'SET_ACCENT':
      return {
        ...state,
        accent: { primary: action.hex },
      };

    case 'RESET':
      return DEFAULT_TOKENS;

    default:
      return state;
  }
}

// ============================================================
// CONTEXT
// ============================================================

interface DesignTokenContextValue {
  tokens: DesignTokens;
  setTypography: (mode: TypographyMode) => void;
  setDensity: (level: DensityLevel) => void;
  setAccent: (hex: string) => void;
  resetTokens: () => void;
  /** CSS custom properties derived from current tokens — spread onto the canvas root */
  cssVars: Record<string, string>;
}

const DesignTokenContext = createContext<DesignTokenContextValue | null>(null);

// ============================================================
// PROVIDER
// ============================================================

export function DesignTokenProvider({ children }: { children: ReactNode }) {
  const [tokens, dispatch] = useReducer(tokenReducer, DEFAULT_TOKENS);

  const setTypography = useCallback((mode: TypographyMode) => {
    dispatch({ type: 'SET_TYPOGRAPHY', mode });
  }, []);

  const setDensity = useCallback((level: DensityLevel) => {
    dispatch({ type: 'SET_DENSITY', level });
  }, []);

  const setAccent = useCallback((hex: string) => {
    dispatch({ type: 'SET_ACCENT', hex });
  }, []);

  const resetTokens = useCallback(() => {
    dispatch({ type: 'RESET' });
  }, []);

  // Derive CSS custom properties — these get spread onto the canvas <div>
  // so every child inherits them without individual re-renders.
  const cssVars = useMemo<Record<string, string>>(() => {
    const fontFamily =
      tokens.typography.mode === 'serif'
        ? tokens.typography.serifStack
        : tokens.typography.sansStack;

    return {
      '--r-font-family': fontFamily,
      '--r-line-height': String(tokens.density.lineHeight),
      '--r-section-gap': `${tokens.density.sectionGap}px`,
      '--r-item-gap': `${tokens.density.itemGap}px`,
      '--r-margin-bottom': `${tokens.density.marginBottom}px`,
      '--r-accent': tokens.accent.primary,
      // Derived shades for subtle backgrounds / hover states
      '--r-accent-light': `${tokens.accent.primary}1a`,   // 10% opacity
      '--r-accent-muted': `${tokens.accent.primary}40`,   // 25% opacity
    };
  }, [tokens]);

  const value = useMemo(
    () => ({ tokens, setTypography, setDensity, setAccent, resetTokens, cssVars }),
    [tokens, setTypography, setDensity, setAccent, resetTokens, cssVars],
  );

  return (
    <DesignTokenContext.Provider value={value}>
      {children}
    </DesignTokenContext.Provider>
  );
}

// ============================================================
// HOOK
// ============================================================

export function useDesignTokens(): DesignTokenContextValue {
  const ctx = useContext(DesignTokenContext);
  if (!ctx) throw new Error('useDesignTokens must be used inside <DesignTokenProvider>');
  return ctx;
}
