import React, { useState, useRef, useEffect } from 'react';
import { Link } from 'react-router-dom';
import { useBrand } from '../../context/BrandContext';

export default function ProductSwitcher() {
  const brand = useBrand();
  const [open, setOpen] = useState(false);
  const ref = useRef<HTMLDivElement>(null);

  useEffect(() => {
    function handleClick(e: MouseEvent) {
      if (ref.current && !ref.current.contains(e.target as Node)) setOpen(false);
    }
    document.addEventListener('click', handleClick);
    return () => document.removeEventListener('click', handleClick);
  }, []);

  const items = [
    { key: 'dashboard', product: brand.products.dashboard },
    { key: 'applications', product: brand.products.applications },
    { key: 'news', product: brand.products.news },
    { key: 'learn', product: brand.products.learn },
  ];

  return (
    <div ref={ref} className="product-switcher">
      <button
        className="app-grid-btn"
        onClick={() => setOpen(v => !v)}
        aria-label="Switch product"
      >
        <svg width="20" height="20" viewBox="0 0 20 20" fill="currentColor">
          <rect x="1" y="1" width="4.5" height="4.5" rx="1" />
          <rect x="7.75" y="1" width="4.5" height="4.5" rx="1" />
          <rect x="14.5" y="1" width="4.5" height="4.5" rx="1" />
          <rect x="1" y="7.75" width="4.5" height="4.5" rx="1" />
          <rect x="7.75" y="7.75" width="4.5" height="4.5" rx="1" />
          <rect x="14.5" y="7.75" width="4.5" height="4.5" rx="1" />
          <rect x="1" y="14.5" width="4.5" height="4.5" rx="1" />
          <rect x="7.75" y="14.5" width="4.5" height="4.5" rx="1" />
          <rect x="14.5" y="14.5" width="4.5" height="4.5" rx="1" />
        </svg>
      </button>

      {open && (
        <div
          className="app-grid-popup"
          style={{ display: 'grid' }}
        >
          {items.map(({ key, product }) => {
            const isActive = product.id === brand.activeProduct.id;
            const isPlaceholder = product.id === 'learn';
            const href = product.homePath;
            const className = `app-grid-item${isActive ? ' active' : ''}${isPlaceholder ? ' coming-soon' : ''}`;

            const content = (
              <>
                <div style={{ position: 'relative', display: 'inline-block' }}>
                  <div
                    className="app-grid-icon"
                    style={{ background: product.primaryColor }}
                  >
                    <i className={`fa-solid ${product.icon}`} />
                  </div>
                  {isPlaceholder && (
                    <span
                      className="app-grid-badge inline-badge"
                      style={{
                        position: 'absolute',
                        top: '-0.2rem',
                        right: '-0.3rem',
                        background: 'var(--text-secondary)',
                        color: '#fff',
                        lineHeight: 1,
                        zIndex: 1,
                      }}
                    >
                      Soon
                    </span>
                  )}
                </div>
                <span>{product.shortName}</span>
              </>
            );

            if (isPlaceholder) {
              return (
                <span
                  key={key}
                  className={className}
                  title="Coming Soon"
                  style={{ opacity: 0.45, pointerEvents: 'none' }}
                >
                  {content}
                </span>
              );
            }

            return (
              <Link
                key={key}
                to={href}
                className={className}
                title={product.name}
                onClick={() => setOpen(false)}
              >
                {content}
              </Link>
            );
          })}
        </div>
      )}
    </div>
  );
}
