import React, { useState, useEffect, useCallback } from 'react';
import { useBrand } from '../../context/BrandContext';

interface BeforeInstallPromptEvent extends Event {
  prompt: () => Promise<void>;
  userChoice: Promise<{ outcome: 'accepted' | 'dismissed' }>;
}

const DISMISS_KEY = 'tms_pwa_dismissed';

export default function PwaInstallPrompt() {
  const brand = useBrand();
  const [deferredPrompt, setDeferredPrompt] = useState<BeforeInstallPromptEvent | null>(null);
  const [dismissed, setDismissed] = useState(() => !!localStorage.getItem(DISMISS_KEY));

  useEffect(() => {
    function handler(e: Event) {
      e.preventDefault();
      setDeferredPrompt(e as BeforeInstallPromptEvent);
    }
    window.addEventListener('beforeinstallprompt', handler);
    return () => window.removeEventListener('beforeinstallprompt', handler);
  }, []);

  const handleInstall = useCallback(async () => {
    if (!deferredPrompt) return;
    await deferredPrompt.prompt();
    const { outcome } = await deferredPrompt.userChoice;
    if (outcome === 'accepted') {
      setDeferredPrompt(null);
    }
  }, [deferredPrompt]);

  const handleDismiss = useCallback(() => {
    setDismissed(true);
    localStorage.setItem(DISMISS_KEY, 'true');
  }, []);

  if (!deferredPrompt || dismissed) return null;

  return (
    <div className="glass-panel" style={{
      position: 'fixed',
      bottom: '1.5rem',
      left: '1.5rem',
      maxWidth: '320px',
      padding: '1.25rem',
      zIndex: 800,
    }}>
      <h4 style={{ margin: '0 0 0.5rem', color: 'var(--text-primary)', fontSize: '0.95rem' }}>
        <i className="fa-solid fa-mobile-screen" style={{ color: brand.primaryColor, marginRight: '0.4rem' }} />
        Install App
      </h4>
      <p style={{ color: 'var(--text-secondary)', fontSize: '0.82rem', margin: '0 0 1rem', lineHeight: 1.5 }}>
        Add TailorMeSwiftly to your home screen for quick access, even offline.
      </p>
      <div style={{ display: 'flex', gap: '0.5rem' }}>
        <button onClick={handleDismiss} className="btn ghost-btn" style={{ fontSize: '0.82rem' }}>
          Not now
        </button>
        <button onClick={handleInstall} className="btn secondary-btn" style={{ flex: 1, fontSize: '0.82rem' }}>
          <i className="fa-solid fa-download" /> Install
        </button>
      </div>
    </div>
  );
}
